"use strict";parserFactory.register("aerialrain.com",()=>new AerialrainParser);class AerialrainParser extends WordpressBaseParser{constructor(){super()}async getChapterUrls(r){return[...r.querySelectorAll("ul.frame-links-list a")].map(r=>util.hyperLinkToChapter(r)).reverse()}findCoverImageUrl(r){return util.getFirstImgSrc(r,"div.entry-content")}getInformationEpubItemChildNodes(r){return[...r.querySelectorAll("div.blog-detail-description p")]}}